class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def dfs(self, root, count):
        if not root:
            return 0
        left_sum = self.dfs(root.left, count)
        right_sum = self.dfs(root.right, count)
        if root.val == left_sum + right_sum:
            count[0] += 1
        return root.val + left_sum + right_sum

    def equalToDescendants(self, root):
        count = [0]
        self.dfs(root, count)
        return count[0]
```

