    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Solution {
    private int dfs(TreeNode root, int[] count) {
        if(root == null) return 0;
        int left_sum = dfs(root.left, count);
        int right_sum = dfs(root.right, count);
        if(root.val == left_sum + right_sum) count[0]++;
        return root.val + left_sum + right_sum;
    }

    public int equalToDescendants(TreeNode root) {
        int[] count = new int[1];
        dfs(root, count);
        return count[0];
    }
}
